// Curriculum Manager: Pick next pending lessons from curriculum
// In production, this reads from Google Sheets. For now, uses embedded curriculum.

const MAX_BATCH_SIZE = 5;

// This would normally be a Google Sheets API call:
// GET https://sheets.googleapis.com/v4/spreadsheets/{sheetId}/values/curriculum!A:H
const curriculum = [
  { lessonId: 'CDE-001', topic: 'Saludos dominicanos', title: 'Que lo que! - How Dominicans Say What\'s Up', slangFocus: ['que lo que', 'dimelo', 'klk'], culturalContext: 'Dominican greetings vs formal Spanish greetings', difficulty: 'beginner', status: 'pending', priority: 1 },
  { lessonId: 'CDE-002', topic: 'La palabra vaina', title: 'Vaina - The Most Dominican Word Ever', slangFocus: ['vaina', 'esa vaina', 'que vaina'], culturalContext: 'How vaina replaces almost any noun in Dominican Spanish', difficulty: 'beginner', status: 'pending', priority: 2 },
  { lessonId: 'CDE-003', topic: 'Pedir comida en la calle', title: 'Ordering Street Food Like a Local', slangFocus: ['dame', 'frio frio', 'chimichurri', 'yaroa'], culturalContext: 'Dominican street food culture and how to order', difficulty: 'beginner', status: 'pending', priority: 3 },
  { lessonId: 'CDE-004', topic: 'Expresiones de sorpresa', title: 'Diache! - Dominican Surprise Expressions', slangFocus: ['diache', 'coño', 'ombe', 'no me diga'], culturalContext: 'How Dominicans express surprise vs other Spanish speakers', difficulty: 'beginner', status: 'pending', priority: 4 },
  { lessonId: 'CDE-005', topic: 'El tigueraje', title: 'What\'s a Tiguere? Dominican Street Smarts', slangFocus: ['tiguere', 'tiguerazo', 'ta loco'], culturalContext: 'The concept of tiguere in Dominican culture', difficulty: 'intermediate', status: 'pending', priority: 5 }
];

// Filter pending lessons sorted by priority
const pendingLessons = curriculum
  .filter(l => l.status === 'pending')
  .sort((a, b) => a.priority - b.priority)
  .slice(0, MAX_BATCH_SIZE);

if (pendingLessons.length === 0) {
  throw new Error('No pending lessons in curriculum');
}

// Return each lesson as a separate item for batch processing
return pendingLessons.map(lesson => ({ json: lesson }));

// Parse and validate the Claude API response
const response = $input.first().json;

// Extract the text content from Claude's response
const textContent = response.content?.find(c => c.type === 'text')?.text;
if (!textContent) {
  throw new Error('No text content in Claude response');
}

// Parse the JSON from Claude's response (handle potential markdown wrapping)
let scriptJson;
try {
  // Try direct parse first
  scriptJson = JSON.parse(textContent);
} catch {
  // Try extracting JSON from markdown code block
  const jsonMatch = textContent.match(/```(?:json)?\s*([\s\S]*?)\s*```/);
  if (jsonMatch) {
    scriptJson = JSON.parse(jsonMatch[1]);
  } else {
    // Try finding JSON object boundaries
    const start = textContent.indexOf('{');
    const end = textContent.lastIndexOf('}');
    if (start !== -1 && end !== -1) {
      scriptJson = JSON.parse(textContent.substring(start, end + 1));
    } else {
      throw new Error('Could not parse JSON from Claude response');
    }
  }
}

// Validate required fields
const required = ['lessonId', 'title', 'lines', 'slangTerms', 'totalCharCount'];
for (const field of required) {
  if (!scriptJson[field]) {
    throw new Error(`Missing required field: ${field}`);
  }
}

// Validate character counts
const domiChars = scriptJson.lines
  .filter(l => l.character === 'DOMI')
  .reduce((sum, l) => sum + l.dialogue.length, 0);
const gringaChars = scriptJson.lines
  .filter(l => l.character === 'GRINGA')
  .reduce((sum, l) => sum + l.dialogue.length, 0);

// Update actual char counts
scriptJson.totalCharCount = {
  domi: domiChars,
  gringa: gringaChars
};

// Budget check
const MONTHLY_CHAR_BUDGET = 30000; // ElevenLabs Starter
const totalChars = domiChars + gringaChars;

const budgetInfo = {
  scriptChars: totalChars,
  domiChars,
  gringaChars,
  withinSingleScriptLimit: domiChars <= 300 && gringaChars <= 250,
  estimatedMonthlyUsage: `${totalChars} of ${MONTHLY_CHAR_BUDGET} chars`
};

// Validate all lines have subtitles
const missingSubtitles = scriptJson.lines.filter(l => !l.subtitle?.es || !l.subtitle?.en);
if (missingSubtitles.length > 0) {
  console.warn(`Warning: ${missingSubtitles.length} lines missing subtitles`);
}

return [{
  json: {
    script: scriptJson,
    budget: budgetInfo,
    status: 'validated',
    generatedAt: new Date().toISOString()
  }
}];

// Store the validated script
// In production, this writes to Google Sheets or maalca-api
// For now, it prepares the data for the next workflow stage

const { script, budget, generatedAt } = $input.first().json;

// Log for monitoring
console.log(`[scriptwriter] Generated: ${script.lessonId} - ${script.title}`);
console.log(`[scriptwriter] Chars: Domi=${budget.domiChars}, Gringa=${budget.gringaChars}, Total=${budget.scriptChars}`);
console.log(`[scriptwriter] Within limits: ${budget.withinSingleScriptLimit}`);

// Prepare output for storage and next workflow trigger
return [{
  json: {
    lessonId: script.lessonId,
    title: script.title,
    brandId: 'curso-de-espanol',
    script: script,
    charCount: {
      domi: budget.domiChars,
      gringa: budget.gringaChars,
      total: budget.scriptChars
    },
    status: 'script_ready',
    generatedAt: generatedAt,
    // This data will be sent to the voice generation workflow
    nextStage: {
      webhook: '/content/generate-voice',
      payload: {
        lessonId: script.lessonId,
        brandId: 'curso-de-espanol',
        script: script
      }
    }
  }
}];

// Error handler: log and notify
const error = $input.first().json;
console.error('[scriptwriter] Pipeline error:', JSON.stringify(error));

// In production, send notification via email/Slack/webhook to maalca-web
return [{
  json: {
    error: true,
    stage: 'script_generation',
    message: error.message || 'Unknown error in script generation',
    timestamp: new Date().toISOString()
  }
}];
